import time
from collections import OrderedDict


class LRUCache:
    """Thread-safe LRU cache with TTL support."""

    def __init__(self, max_size=100, default_ttl=300):
        self.max_size = max_size
        self.default_ttl = default_ttl
        self._store = OrderedDict()
        self._expiry = {}

    def get(self, key, default=None):
        """Get a value from the cache."""
        if key not in self._store:
            return default
        if self._is_expired(key):
            self._remove(key)
            return default
        self._store.move_to_end(key)
        return self._store[key]

    def set(self, key, value, ttl=None):
        """Set a value in the cache with optional TTL."""
        if ttl is None:
            ttl = self.default_ttl
        if key in self._store:
            self._store.move_to_end(key)
            self._store[key] = value
            self._expiry[key] = time.time() + ttl
        else:
            if len(self._store) >= self.max_size:
                self._evict()
            self._store[key] = value
            self._expiry[key] = time.time() + ttl

    def delete(self, key):
        """Delete a key from the cache."""
        if key in self._store:
            self._remove(key)
            return True
        return False

    def clear(self):
        """Clear all entries."""
        self._store.clear()
        self._expiry.clear()

    def size(self):
        """Return number of entries."""
        return len(self._store)

    def keys(self):
        """Return all non-expired keys."""
        self._cleanup_expired()
        return list(self._store.keys())

    def _is_expired(self, key):
        """Check if a key has expired."""
        return key in self._expiry and time.time() > self._expiry[key]

    def _remove(self, key):
        """Remove a key from the cache."""
        del self._store[key]
        del self._expiry[key]

    def _evict(self):
        """Evict entries to make room.

        BUG: This evicts ALL expired entries AND the oldest 25% of remaining
        entries, even when only 1 slot is needed. This is way too aggressive —
        it should only remove enough entries to make room for one new entry.
        """
        # First remove all expired
        expired = [k for k in list(self._store) if self._is_expired(k)]
        for k in expired:
            self._remove(k)

        # BUG: Also remove oldest 25% of remaining entries
        if len(self._store) >= self.max_size:
            remove_count = max(1, len(self._store) // 4)
            for _ in range(remove_count):
                oldest_key, _ = self._store.popitem(last=False)
                del self._expiry[oldest_key]

    def _cleanup_expired(self):
        """Remove all expired entries."""
        expired = [k for k in list(self._store) if self._is_expired(k)]
        for k in expired:
            self._remove(k)

