import time
from cache.decorators import memoize


class TestMemoize:
    def test_caches_result(self):
        call_count = 0

        @memoize()
        def expensive(x):
            nonlocal call_count
            call_count += 1
            return x * 2

        assert expensive(5) == 10
        assert expensive(5) == 10
        assert call_count == 1

    def test_different_args(self):
        @memoize()
        def double(x):
            return x * 2

        assert double(3) == 6
        assert double(4) == 8

    def test_cache_clear(self):
        call_count = 0

        @memoize()
        def compute(x):
            nonlocal call_count
            call_count += 1
            return x + 1

        compute(1)
        compute.cache_clear()
        compute(1)
        assert call_count == 2
